            visited[i] = true;
            while (queue.length > 0) {
                const node = queue.shift()!;
                component.push(node);
                for (const neighbor of adj[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        queue.push(neighbor);
                    }
