function solve(c: number, connections: number[][], queries: number[][]): number[] {
    class DSU {
        parent: number[];
        rank: number[];
        constructor(n: number) {
            this.parent = Array(n + 1).fill(0).map((_, i) => i);
            this.rank = Array(n + 1).fill(0);
        }
        find(u: number): number {
            if (this.parent[u] !== u) {
                this.parent[u] = this.find(this.parent[u]);
            }
            return this.parent[u];
        }
        union(u: number, v: number): boolean {
            const rootU = this.find(u);
            const rootV = this.find(v);
            if (rootU === rootV) return false;
            if (this.rank[rootU] < this.rank[rootV]) {
                this.parent[rootU] = rootV;
            } else {
                this.parent[rootV] = rootU;
                if (this.rank[rootU] === this.rank[rootV]) {
                    this.rank[rootU]++;
                }
            }
            return true;
        }
    }

    class MinHeap {
        private heap: number[];
        constructor() {
            this.heap = [];
        }
        push(value: number): void {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop(): number {
            if (this.heap.length === 0) return -1;
            const top = this.heap[0];
            this.heap[0] = this.heap.pop() as number;
            this.heapifyDown(0);
            return top;
        }
        peek(): number {
            return this.heap[0];
        }
        isEmpty(): boolean {
            return this.heap.length === 0;
        }
        private heapifyUp(index: number): void {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[parentIndex] <= this.heap[index]) break;
                [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
                index = parentIndex;
            }
        }
        private heapifyDown(index: number): void {
            const n = this.heap.length;
            while (index < n) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < n && this.heap[left] < this.heap[smallest]) smallest = left;
                if (right < n && this.heap[right] < this.heap[smallest]) smallest = right;
                if (smallest === index) break;
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            }
        }
    }

    const dsu = new DSU(c);
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    const rootToNodes = new Map<number, number[]>();
    for (let i = 1; i <= c; i++) {
        const root = dsu.find(i);
        if (!rootToNodes.has(root)) {
            rootToNodes.set(root, []);
        }
        rootToNodes.get(root)!.push(i);
    }

    const componentHeaps = new Map<number, MinHeap>();
    for (const [root, nodes] of rootToNodes.entries()) {
        const heap = new MinHeap();
        for (const node of nodes) {
            heap.push(node);
        }
        componentHeaps.set(root, heap);
    }

    const online = new Array(c + 1).fill(true);

    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 2) {
            online[x] = false;
        } else {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const heap = componentHeaps.get(root);
                if (!heap) {
                    result.push(-1);
                    continue;
                }
                while (!heap.isEmpty()) {
                    const top = heap.peek();
                    if (online[top]) {
                        result.push(top);
                        break;
                    } else {
                        heap.pop();
                    }
                }
                if (heap.isEmpty()) {
                    result.push(-1);
                }
            }
        }
    }

    return result;
}
